// Solar-Beschattung + Nacht + Aussenlicht
// NOAA-Sonnenzeiten (Hamburg 53.55N, 10.0E)
// 
// REGELN:
// - Nur E/W-Geräte beschatten, N-Geräte immer offen (ausser nachts)
// - Schlafzimmer am Wochenende: keine Beschattung, nur Schedule
// - Schlafzimmer Mo-Fr: nicht vor 07:00 öffnen
// - Nach einer Aktion wird die Position gespeichert — kein erneutes Senden
//   solange sich der Zielwert nicht ändert (manuelle Bedienung bleibt erhalten)

const LOCATION = { lat: 53.55, lon: 10.0 };
const AUSSENLICHT = 'shelly1-E098068CC9EB';

function sunTimes(date, lat, lon) {
    const D2R = Math.PI / 180, R2D = 180 / Math.PI;
    const doy = Math.floor((date - new Date(Date.UTC(date.getFullYear(), 0, 0))) / 86400000);
    const gamma = doy * D2R * 360 / 365;
    const eqTime = 229.18 * (0.000075 + 0.001868 * Math.cos(gamma) - 0.032077 * Math.sin(gamma)
        - 0.014615 * Math.cos(2 * gamma) - 0.040849 * Math.sin(2 * gamma));
    const decl = 0.006918 - 0.399912 * Math.cos(gamma) + 0.070257 * Math.sin(gamma)
        - 0.006758 * Math.cos(2 * gamma) + 0.000907 * Math.sin(2 * gamma)
        - 0.002697 * Math.cos(3 * gamma) + 0.00148 * Math.sin(3 * gamma);
    const cosH = (Math.cos(90.833 * D2R) - Math.sin(lat * D2R) * Math.sin(decl))
        / (Math.cos(lat * D2R) * Math.cos(decl));
    let sunrise, sunset, noon;
    if (cosH > 1) { sunrise = 0; sunset = 24; noon = 12; }
    else if (cosH < -1) { sunrise = 12; sunset = 12; noon = 12; }
    else {
        const ha = Math.acos(cosH) * R2D;
        const noonUTC = 12 - lon / 15 + eqTime / 60;
        sunrise = noonUTC - ha / 15;
        sunset = noonUTC + ha / 15;
        noon = noonUTC;
    }
    const tzOff = -date.getTimezoneOffset() / 60;
    return { sunrise: sunrise + tzOff, sunset: sunset + tzOff, noon: noon + tzOff };
}

function decodeSenecValue(data) {
    if (data === undefined || data === null) return NaN;
    if (typeof data === 'number') return data;
    if (typeof data !== 'string') return NaN;
    const tmp = data.split('_');
    if (tmp.length < 2) return Number(data);
    const type = tmp[0], value = tmp[1];
    if (type === 'fl') {
        const buf = Buffer.from(value, 'hex');
        return Math.round(buf.readFloatBE(0) * 100) / 100;
    }
    if (['u8','u1','u3','u6'].includes(type)) return parseInt(value, 16);
    if (['i1','i3','i8'].includes(type)) return parseInt(value, 16);
    return Number(value);
}

// --- Geräte mit Richtung (E=Ost, W=West, N=Nord/keine Beschattung) ---
// MQTT: Gen1 -> shellies/<id>/roller/0/command/pos mit Zahl
//       Gen2/4 -> <id>/rpc mit JSON RPC

const devices = {
    east: [
        {name:'Kueche2',         shelly:'shellyswitch25-1099F3', closePos: 20},
        {name:'GaesteBad',       shelly:'shellyswitch25-109DA4'},
        {name:'Badezimmer',      shelly:'shellyplus2pm-ecc9ffc14310', gen:2},
        {name:'Arbeitszimmer2',  shelly:'shelly2pmg4-48f6eedad190', gen:4}
    ],
    west: [
        {name:'Wohnzimmer1',     shelly:'shellyswitch25-10A277'},
        {name:'Wohnzimmer2',     shelly:'shelly2pmg4-58e6c530408c', gen:4},
        {name:'Schlafzimmer1',   shelly:'shellyswitch25-F3FDC4', bedroom: true},
        {name:'Schlafzimmer2',   shelly:'shellyswitch25-10A1DE', bedroom: true}
    ],
    north: [
        {name:'Kueche1',         shelly:'shelly2pmg4-58e6c5324770', closePos: 20, gen:4},
        {name:'Schlafzimmer3',   shelly:'shellyswitch25-1097AB', bedroom: true},
        {name:'Arbeitszimmer1',  shelly:'shellyswitch25-10986E'},
        {name:'Till',            shelly:'shellyswitch25-109899', bedroom: true},
        {name:'Jan',             shelly:'shelly2pmg4-e8f60a60b50c', gen:4, bedroom: true}
    ]
};

const allDevices = [...devices.east, ...devices.west, ...devices.north];
const bedrooms = allDevices.filter(d => d.bedroom);

const cfg = {
    shadeOnW: 2500,       // Beschattung einschalten
    shadeOffW: 1200,     // Beschattung ausschalten (Hysterese)
    shadePos: 50,
    closePos: 0,
    openPos: 100,
    bedroomEarliestOpen: 7,     // Schlafzimmer Mo-Fr nicht vor 7:00
    lightOffNightHour: 1,
    lightMorningCloudyW: 500
};

// --- Energie + Zeit ---
const energy = msg.payload && msg.payload.ENERGY ? msg.payload.ENERGY : {};
const pvW = decodeSenecValue(energy.GUI_INVERTER_POWER);
const now = new Date();
const hour = now.getHours() + now.getMinutes() / 60;
const dayOfWeek = now.getDay();  // 0=So, 6=Sa
const isWeekend = dayOfWeek === 0 || dayOfWeek === 6;
const sunny = pvW >= cfg.shadeOnW;
const cloudy = pvW < cfg.shadeOffW;  // Hysterese: erst unter 1200W öffnen
const sun = sunTimes(now, LOCATION.lat, LOCATION.lon);

let phase = 'night';
if (hour >= sun.sunrise && hour < sun.noon) phase = 'east';
else if (hour >= sun.noon && hour < sun.sunset) phase = 'west';

// --- Zustand speichern (flow context) um Wiederholungen zu vermeiden ---
let lastPos = flow.get('shadingLastPos') || {};
let newCommands = [];
const ts = now.toISOString();

function pushCmd(d, pos) {
    const key = d.shelly;
    if (lastPos[key] === pos) return; // bereits gesendet, keine Änderung
    lastPos[key] = pos;
    if (d.gen >= 2) {
        newCommands.push({topic: d.shelly + '/rpc',
            payload: {id:1, src:'nodered', method:'Cover.GoToPosition', params:{id:0, pos:pos}}});
    } else {
        newCommands.push({topic: 'shellies/' + d.shelly + '/roller/0/command/pos', payload: pos});
    }
}

// === Jalousien-Logik ===

function shadeGroup(group, pos, reason) {
    for (const d of group) {
        // Schlafzimmer am Wochenende nicht beschatten
        if (d.bedroom && isWeekend) continue;
        // Schlafzimmer Mo-Fr nicht vor 07:00
        if (d.bedroom && !isWeekend && hour < cfg.bedroomEarliestOpen) continue;
        pushCmd(d, pos);
    }
    if (reason) node.warn(ts + ' ' + reason);
}

if (phase === 'east') {
    if (sunny) {
        shadeGroup(devices.east, cfg.shadePos,
            'OST-SCHATTEN: ' + devices.east.map(d=>d.name).join(',') + ' -> ' + cfg.shadePos + '% (PV=' + pvW.toFixed(0) + 'W)');
    } else if (cloudy) {
        // Hysterese: PV unter 1200W -> Beschattung lösen
        for (const d of devices.east) pushCmd(d, cfg.openPos);
    }
    // West + North tagsüber öffnen (Schlafzimmer-Regeln beachten)
    const openWest = devices.west.filter(d => {
        if (d.bedroom && isWeekend) return false;
        if (d.bedroom && !isWeekend && hour < cfg.bedroomEarliestOpen) return false;
        return true;
    });
    const openNorth = devices.north.filter(d => {
        if (d.bedroom && isWeekend) return false;
        if (d.bedroom && !isWeekend && hour < cfg.bedroomEarliestOpen) return false;
        return true;
    });
    for (const d of [...openWest, ...openNorth]) pushCmd(d, cfg.openPos);
} else if (phase === 'west') {
    // Ost öffnen
    for (const d of devices.east) pushCmd(d, cfg.openPos);
    if (sunny) {
        shadeGroup(devices.west, cfg.shadePos,
            'WEST-SCHATTEN: ' + devices.west.map(d=>d.name).join(',') + ' -> ' + cfg.shadePos + '% (PV=' + pvW.toFixed(0) + 'W)');
    } else if (cloudy) {
        for (const d of devices.west) {
            if (d.bedroom && isWeekend) continue;
            if (d.bedroom && !isWeekend && hour < cfg.bedroomEarliestOpen) continue;
            pushCmd(d, cfg.openPos);
        }
    }
    // North offen halten (Schlafzimmer-Regeln beachten)
    for (const d of devices.north) {
        if (d.bedroom && isWeekend) continue;
        if (d.bedroom && !isWeekend && hour < cfg.bedroomEarliestOpen) continue;
        pushCmd(d, cfg.openPos);
    }
} else {
    // Nacht: alles schließen
    for (const d of allDevices) {
        const pos = d.closePos !== undefined ? d.closePos : cfg.closePos;
        pushCmd(d, pos);
    }
}

// === Aussenlicht ===
const lightTopic = 'shellies/' + AUSSENLICHT + '/relay/0/command';
const isDark = (hour >= sun.sunset) || (hour < sun.sunrise);

if (isDark) {
    const deepNight = hour >= cfg.lightOffNightHour && hour < sun.sunrise;
    if (deepNight) {
        newCommands.push({topic: lightTopic, payload: 'off'});
    } else {
        newCommands.push({topic: lightTopic, payload: 'on'});
    }
} else if (phase === 'east' && !sunny && pvW < cfg.lightMorningCloudyW) {
    newCommands.push({topic: lightTopic, payload: 'on'});
} else if (phase === 'east' && pvW >= cfg.lightMorningCloudyW) {
    newCommands.push({topic: lightTopic, payload: 'off'});
}

// Speichern
flow.set('shadingLastPos', lastPos);

function fmtHour(h) {
    const hh = Math.floor(h), mm = Math.round((h - hh) * 60);
    return String(hh).padStart(2,'0') + ':' + String(mm).padStart(2,'0');
}

node.status({
    fill: newCommands.length > 0 ? 'green' : 'blue',
    shape: 'dot',
    text: (newCommands.length>0?'\u26a1':'·') + ' PV=' + pvW.toFixed(0) + 'W ' + phase
        + (isWeekend?' WE':'') + (sunny?' sonnig':cloudy?' wolkig':'')
        + ' \u2600' + fmtHour(sun.sunrise) + ' \uD83C\uDF19' + fmtHour(sun.sunset)
        + ' | ' + newCommands.length + ' cmd'
});

if (newCommands.length === 0) return null;
return [newCommands];

// Rollo-Steuerung: nimmt room + action/pos, sendet MQTT-Kommandos.
// GET: /rollo?room=kueche1&pos=50
// POST: {"room": "kueche1", "pos": 50} oder {"room":"wohnzimmer","action":"zu"}

const devices = {
    'kueche1':          {shelly:'shelly2pmg4-58e6c5324770', gen:4, raum:'Küche'},
    'kueche2':          {shelly:'shellyswitch25-1099F3', raum:'Küche'},
    'gaestebad':        {shelly:'shellyswitch25-109DA4', raum:'GästeBad'},
    'gaestewc':         {shelly:'shellyswitch25-109DA4', raum:'GästeBad'},
    'wohnzimmer1':      {shelly:'shellyswitch25-10A277', raum:'Wohnzimmer'},
    'wohnzimmer2':      {shelly:'shelly2pmg4-58e6c530408c', gen:4, raum:'Wohnzimmer'},
    'schlafzimmer1':    {shelly:'shellyswitch25-F3FDC4', raum:'Schlafzimmer'},
    'schlafzimmer2':    {shelly:'shellyswitch25-10A1DE', raum:'Schlafzimmer'},
    'schlafzimmer3':    {shelly:'shellyswitch25-1097AB', raum:'Schlafzimmer'},
    'arbeitszimmer1':   {shelly:'shellyswitch25-10986E', raum:'Arbeitszimmer'},
    'arbeitszimmer2':   {shelly:'shelly2pmg4-48f6eedad190', gen:4, raum:'Arbeitszimmer'},
    'badezimmer':       {shelly:'shellyplus2pm-ecc9ffc14310', gen:2, raum:'Badezimmer'},
    'till':             {shelly:'shellyswitch25-109899', raum:'Till'},
    'jan':              {shelly:'shelly2pmg4-e8f60a60b50c', gen:4, raum:'Jan'}
};

// Raum-Aliase: "wohnzimmer" -> wohnzimmer1+wohnzimmer2
const raumAliases = {
    'kueche':           ['kueche1','kueche2'],
    'wohnzimmer':       ['wohnzimmer1','wohnzimmer2'],
    'schlafzimmer':     ['schlafzimmer1','schlafzimmer2','schlafzimmer3'],
    'arbeitszimmer':    ['arbeitszimmer1','arbeitszimmer2'],
    'erdgeschoss':      ['kueche1','kueche2','gaestebad','wohnzimmer1','wohnzimmer2'],
    'eg':               ['kueche1','kueche2','gaestebad','wohnzimmer1','wohnzimmer2'],
    '1og':              ['schlafzimmer1','schlafzimmer2','schlafzimmer3','arbeitszimmer1','arbeitszimmer2','badezimmer'],
    'erstesog':         ['schlafzimmer1','schlafzimmer2','schlafzimmer3','arbeitszimmer1','arbeitszimmer2','badezimmer'],
    'obergeschoss':     ['schlafzimmer1','schlafzimmer2','schlafzimmer3','arbeitszimmer1','arbeitszimmer2','badezimmer'],
    '2og':              ['till','jan'],
    'dachgeschoss':     ['till','jan'],
    'alle':             ['kueche1','kueche2','gaestebad','wohnzimmer1','wohnzimmer2',
                          'schlafzimmer1','schlafzimmer2','schlafzimmer3',
                          'arbeitszimmer1','arbeitszimmer2','badezimmer','till','jan']
};

const q = msg.req && msg.req.query ? msg.req.query : {};
const body = typeof msg.payload === 'object' ? msg.payload : {};
const room = (body.room || q.room || '').toLowerCase().replace(/[äöüß]/g, m => ({'ä':'ae','ö':'oe','ü':'ue','ß':'ss'})[m]);
let action = body.action || q.action || '';
let pos = body.pos || q.pos || '';

// Action zu Position übersetzen
if (action) {
    const a = action.toLowerCase();
    if (['auf','hoch','rauf','open','öffnen','oeffnen'].includes(a)) pos = 100;
    else if (['zu','runter','ab','close','schließen','schliessen'].includes(a)) pos = 0;
    else if (['stop','stopp','halt'].includes(a)) pos = 'stop';
    else { msg.payload = {error:'Unbekannte Aktion: '+action}; return [null, msg]; }
}

if (pos === '' || pos === undefined) {
    msg.payload = {error:'Keine Position/Aktion angegeben. Nutze ?room=...&pos=50 oder &action=zu'};
    return [null, msg];
}

// Räume auflösen
let targets = raumAliases[room] || [room];
let commands = [];
let notFound = [];

for (const r of targets) {
    const dev = devices[r];
    if (!dev) { notFound.push(r); continue; }
    if (pos === 'stop') {
        commands.push({
            topic: dev.gen >= 2 ? dev.shelly + '/rpc' : 'shellies/' + dev.shelly + '/roller/0/command',
            payload: dev.gen >= 2 ? {id:1, src:'nodered', method:'Cover.Stop', params:{id:0}} : 'stop'
        });
    } else {
        const p = parseInt(pos);
        if (isNaN(p) || p < 0 || p > 100) {
            msg.payload = {error:'Position muss 0-100 sein: '+pos};
            return [null, msg];
        }
        commands.push({
            topic: dev.gen >= 2 ? dev.shelly + '/rpc' : 'shellies/' + dev.shelly + '/roller/0/command/pos',
            payload: dev.gen >= 2 ? {id:1, src:'nodered', method:'Cover.GoToPosition', params:{id:0, pos:p}} : p
        });
    }
}

if (notFound.length && commands.length === 0) {
    msg.payload = {error:'Raum nicht gefunden: ' + notFound.join(', ')};
    return [null, msg];
}

msg.payload = {
    ok: true,
    rooms: targets.filter(r => devices[r]).map(r => devices[r].raum || r),
    notFound: notFound,
    commands: commands.length,
    pos: pos
};
// Ausgabe 1: MQTT-Kommandos, Ausgabe 2: HTTP-Antwort
return [commands.length > 0 ? commands : null, msg];
